const threshold = 10; // % — anything above this is flagged as anomalous

const results = [];
for (const item of $input.all()) {
  const d = item.json;
  const nrwPct = ((d.inflow_lpm - d.outflow_lpm) / d.inflow_lpm) * 100;

  results.push({
    json: {
      ...d,
      nrw_pct: parseFloat(nrwPct.toFixed(2)),
      is_anomaly: nrwPct > threshold
    }
  });
}
return results;

const zones = ['Zone_A', 'Zone_B', 'Zone_C', 'Zone_D'];
const output = [];

for (const zone of zones) {
  const isContaminated = Math.random() < 0.5;

  const ph = isContaminated
    ? (Math.random() < 0.5 ? 5.0 + Math.random() * 0.8 : 9.0 + Math.random() * 0.8) // out of safe range
    : 6.8 + Math.random() * 1.2; // normal safe range ~6.8-8.0

  const turbidity = isContaminated
    ? 8 + Math.random() * 12 // NTU, elevated/unsafe
    : 0.5 + Math.random() * 3; // normal, clear water

  const chlorine = isContaminated
    ? Math.random() * 0.15 // too low, recontamination risk
    : 0.3 + Math.random() * 0.7; // normal residual disinfectant

  const temperature = 18 + Math.random() * 10; // celsius, ambient variation

  output.push({
    json: {
      timestamp: new Date().toISOString(),
      zone_id: zone,
      ph: parseFloat(ph.toFixed(2)),
      turbidity_ntu: parseFloat(turbidity.toFixed(2)),
      chlorine_mgl: parseFloat(chlorine.toFixed(2)),
      temperature_c: parseFloat(temperature.toFixed(2)),
      is_simulated_contamination: isContaminated
    }
  });
}

return output;

const results = [];

for (const item of $input.all()) {
  const d = item.json;
  const issues = [];

  if (d.ph < 6.5 || d.ph > 8.5) issues.push(`pH out of safe range (${d.ph})`);
  if (d.turbidity_ntu > 5) issues.push(`turbidity too high (${d.turbidity_ntu} NTU)`);
  if (d.chlorine_mgl < 0.2) issues.push(`chlorine residual too low (${d.chlorine_mgl} mg/L)`);

  results.push({
    json: {
      ...d,
      is_anomaly: issues.length > 0,
      issues: issues.join('; ') || 'none'
    }
  });
}

return results;

const currentYear = 2026;
const today = new Date('2026-07-16'); // matches your current project date

const results = [];

for (const item of $input.all()) {
  const d = item.json;

  const age = currentYear - parseInt(d.install_year);
  const lastMaint = new Date(d.last_maintenance_date);
  const daysSinceMaintenance = Math.floor((today - lastMaint) / (1000 * 60 * 60 * 24));
  const runtimeHours = parseFloat(d.total_runtime_hours);
  const failures = parseInt(d.failure_count);

  // Simple weighted risk score — not real engineering formula, but defensible for a demo:
  // age matters, time overdue matters more, runtime wear matters, past failures compound risk
  let riskScore = 0;
  riskScore += age * 2;                          // older = riskier
  riskScore += Math.max(0, daysSinceMaintenance - 180) * 0.3; // penalty grows after 6 months overdue
  riskScore += (runtimeHours / 1000) * 1.5;       // wear from usage
  riskScore += failures * 8;                      // past failures strongly predictive of future ones

  const isAtRisk = riskScore > 70; // threshold — tune this after seeing real distribution

  results.push({
    json: {
      ...d,
      age_years: age,
      days_since_maintenance: daysSinceMaintenance,
      risk_score: parseFloat(riskScore.toFixed(1)),
      is_at_risk: isAtRisk
    }
  });
}

return results;

const zones = ['Zone_A', 'Zone_B', 'Zone_C', 'Zone_D'];
const output = [];

for (const zone of zones) {
  const baseInflow = 100 + Math.random() * 20;
  const isLeak = Math.random() < 0.5;

  let lossPct = 0.02 + Math.random() * 0.02;
  if (isLeak) {
    lossPct = 0.15 + Math.random() * 0.25;
  }

  const outflow = baseInflow * (1 - lossPct);
  const pressure = isLeak
    ? 2.0 + Math.random() * 0.5
    : 3.5 + Math.random() * 0.5;

  output.push({
    json: {
      timestamp: new Date().toISOString(),
      zone_id: zone,
      inflow_lpm: parseFloat(baseInflow.toFixed(2)),
      outflow_lpm: parseFloat(outflow.toFixed(2)),
      pressure_bar: parseFloat(pressure.toFixed(2)),
      is_simulated_leak: isLeak
    }
  });
}

return output;

